var sel = (Tekla.Structures.Model.ModelObjectSelector)model.GetModelObjectSelector();

// #2: count parts by phase
var partsEnum = sel.GetAllObjectsWithType(Tekla.Structures.Model.ModelObject.ModelObjectEnum.BEAM);
var phaseCounts = new System.Collections.Generic.Dictionary<int, int>();
while (partsEnum.MoveNext()) {
    var part = (Tekla.Structures.Model.Part)partsEnum.Current;
    Tekla.Structures.Model.Phase ph;
    part.GetPhase(out ph);
    int phaseNum = ph != null ? ph.PhaseNumber : 0;
    if (!phaseCounts.ContainsKey(phaseNum)) phaseCounts[phaseNum] = 0;
    phaseCounts[phaseNum] += 1;
}

// #3: GUIDs of currently selected parts
var uiSel = new Tekla.Structures.Model.UI.ModelObjectSelector();
var selectedEnum = uiSel.GetSelectedObjects();
var selectedGuids = new System.Collections.Generic.List<string>();
while (selectedEnum.MoveNext()) {
    var mo = (Tekla.Structures.Model.ModelObject)selectedEnum.Current;
    selectedGuids.Add(mo.Identifier.GUID.ToString());
}

// #4: bounding box of all parts (since selection might be empty)
var partsEnum2 = sel.GetAllObjectsWithType(Tekla.Structures.Model.ModelObject.ModelObjectEnum.BEAM);
double minX=double.MaxValue, minY=double.MaxValue, minZ=double.MaxValue;
double maxX=double.MinValue, maxY=double.MinValue, maxZ=double.MinValue;
int partCount = 0;
while (partsEnum2.MoveNext()) {
    var part = (Tekla.Structures.Model.Beam)partsEnum2.Current;
    foreach (var p in new[] { part.StartPoint, part.EndPoint }) {
        if (p.X < minX) minX = p.X; if (p.Y < minY) minY = p.Y; if (p.Z < minZ) minZ = p.Z;
        if (p.X > maxX) maxX = p.X; if (p.Y > maxY) maxY = p.Y; if (p.Z > maxZ) maxZ = p.Z;
    }
    partCount++;
}

return new {
    p2_phase_counts = phaseCounts,
    p3_selected_guids = selectedGuids,
    p3_selected_count = selectedGuids.Count,
    p4_bbox = partCount > 0 ? (object)new {
        min = new { x = minX, y = minY, z = minZ },
        max = new { x = maxX, y = maxY, z = maxZ },
        extent_mm = new { x = maxX - minX, y = maxY - minY, z = maxZ - minZ }
    } : null,
    p4_part_count = partCount
};
